2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - Next Generation", () => {
5	  it("should return empty grid when given empty grid", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should return empty grid when single live cell dies from underpopulation", () => {
9	    expect(nextGeneration([[true]])).toEqual([]);
10	  });
11	  it("should return empty grid when two live cells die from underpopulation", () => {
12	    expect(nextGeneration([[true, true]])).toEqual([]);
13	  });
14	  it("should keep a live cell alive when it has exactly 2 live neighbors", () => {
15	    // A live cell at position [0][1] has 2 live neighbors: [0][0] and [0][2]
16	    expect(nextGeneration([[true, true, true]])).toEqual([[false, true, false]]);
17	  });
18	  it("should keep a live cell alive when it has exactly 3 live neighbors", () => {
19	    // A 2x2 grid: all 4 cells live. Cell [0][0] has exactly 3 live neighbors: [0][1], [1][0], [1][1]
20	    expect(nextGeneration([[true, true], [true, true]])).toEqual([[true, true], [true, true]]);
21	  });
22	  it("should kill a live cell when it has more than 3 live neighbors", () => {
23	    // In a 2x3 all-live grid, the middle cells [0][1] and [1][1] each have 5 live neighbors (>3), so they die
24	    expect(nextGeneration([[true, true, true], [true, true, true]])).toEqual([[true, false, true], [true, false, true]]);
25	  });
26	  it("should bring a dead cell to life when it has exactly 3 live neighbors", () => {
27	    // Dead cell at [1][1] has exactly 3 live neighbors: [0][0], [0][1], [1][0]
28	    expect(nextGeneration([[true, true], [true, false]])).toEqual([[true, true], [true, true]]);
29	  });
30	  it.todo("should compute next generation for blinker pattern");
31	  it.todo("should compute next generation for block still life pattern");
32	});
