  // Input:  [[true, true, true]] (1 row x 3 cols)
  // Output: [[false, true, false], [false, true, false], [false, true, false]] (3 rows x 3 cols)
  //   Row -1 (new): [false, true, false]  <- cell born at (-1,1)
  //   Row  0 (orig): [false, true, false]  <- center survives, edges die
  //   Row +1 (new): [false, true, false]  <- cell born at (+1,1)
  expect(nextGeneration([[true, true, true]])).toEqual([
    [false, true, false],
    [false, true, false],
    [false, true, false],
  ]);
});

